{
  "title": "Primary Science Exam",
   "description": "A basic science exam for primary students",
   "timeLimit": 60,
   "passingScore": 70,
   "sections": [
       {
           "name": "A",
           "description": "Multiple Choice questions",
           "questions": [
               {
                   "text": "What is the largest planet in our solar system?",
                   "type": "multiple-choice",
                   "points": 5,
                   "difficulty": "easy",
                   "options": [
                       {"text": "Earth", "isCorrect": false, "letter": "A"},
                       {"text": "Saturn", "isCorrect": false, "letter": "B"},
                       {"text": "Jupiter", "isCorrect": true, "letter": "C"},
                       {"text": "Uranus", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "C"
               }
           ]
       },
       {
           "name": "B",
           "description": "Open Ended questions",
           "questions": [
               {
                   "text": "What is the process called when plants make their own food from sunlight?",
                   "type": "open-ended",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "Photosynthesis"
               },
               {
                   "text": "Describe the water cycle and its importance to our planet.",
                   "type": "open-ended",
                   "points": 15,
                   "difficulty": "hard",
                   "correctAnswer": "The water cycle is the process by which water is circulated between the Earth and the atmosphere. It involves evaporation, condensation, and precipitation, and is essential for life on Earth."
               }
           ]
       },
       {
           "name": "C",
           "description": "True / False questions",
           "questions": [
               {
                   "text": "The sun is a planet.",
                   "type": "true-false",
                   "points": 5,
                   "difficulty": "easy",
                   "options": [
                       {"text": "True", "isCorrect": false, "letter": "A"},
                       {"text": "False", "isCorrect": true, "letter": "B"}
                   ],
                   "correctAnswer": "False"
               }
           ]
       },
       {
           "name": "D",
           "description": "Short Answer questions",
           "questions": [
               {
                   "text": "What is the main function of the roots of a plant?",
                   "type": "short-answer",
                   "points": 5,
                   "difficulty": "easy",
                   "correctAnswer": "To absorb water and nutrients from the soil"
               }
           ]
       },
       {
           "name": "E",
           "description": "Fill in Blank questions",
           "questions": [
               {
                   "text": "The ___ is the largest mammal on Earth.",
                   "type": "fill-in-blank",
                   "points": 5,
                   "difficulty": "easy",
                   "correctAnswer": "blue whale"
               }
           ]
       },
       {
           "name": "F",
           "description": "Matching questions",
           "questions": [
               {
                   "text": "Match the following animals with their habitats: lion - ___ , penguin - ___ , fish - ___",
                   "type": "matching",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "savannah, Antarctica, ocean"
               }
           ]
       },
       {
           "name": "G",
           "description": "Ordering questions",
           "questions": [
               {
                   "text": "Put the following stages of a butterfly's life cycle in order: pupa, larva, adult, egg",
                   "type": "ordering",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "egg, larva, pupa, adult"
               }
           ]
       }
   ]
}
